#!/usr/bin/env python3
"""
ME-OLE — ME Offline Editor  v0.93
========================
A local web GUI for editing Allen & Heath ME-1 personal monitor mixer config files.

Usage:
    python3 me1_editor.py  # filename unchanged for compatibility

Then open http://localhost:5000 in your browser.

Requirements:
    pip install flask
    me1.py must be in the same directory.
"""

__version__ = "0.93"


import glob
import re
import io
import os
import sys
import tempfile

from flask import Flask, jsonify, render_template_string, request, send_file

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from me1 import (
    ME1Config, Preset, Key,
    LEVEL_OFF, LEVEL_UNITY, _LEVEL_UNSET,
    PAN_LEFT, PAN_CENTRE, PAN_RIGHT,
    SRC_NONE,
    _FLAG_MONO, _FLAG_AUTO, _FLAG_STEREO, _FLAG_GROUP, _FLAG_UNASSIGNED, _FLAG_GROUP_ALT,
    _NKEYS, _NPRESETS,
)

app = Flask(__name__)

STORAGE_DIR = os.environ.get('STORAGE_DIR', '/data/configs')
os.makedirs(STORAGE_DIR, exist_ok=True)

_config: ME1Config = None
_filename: str = "untitled.ME1"

ME1_IMG = "data:image/png;base64,"

# ── Serialisation ─────────────────────────────────────────────────────────────

def key_to_dict(k: Key, idx: int) -> dict:
    if k.is_auxin():
        src_type = "auxin"
    elif k.is_sine():
        src_type = "sine"
    elif k._flag == _FLAG_AUTO:
        src_type = "auto"
    elif k._flag == _FLAG_MONO and k.src_ch == SRC_NONE:
        # Bug B: firmware export quirk — channel byte corrupted to 0xFF.
        # A key is truly unassigned when its label is blank OR its level is sentinel
        # (off/0x80).  Only treat as single_no_ch (assigned, channel lost) when BOTH
        # a non-blank label AND an active level are present — that combination means
        # the user genuinely set this button up but the channel byte was lost.
        _blank_label    = not k.label.strip()
        _sentinel_level = (k.level == LEVEL_OFF)
        if _blank_label or _sentinel_level:
            src_type = "unassigned"
        else:
            src_type = "single_no_ch"   # assigned, channel lost to firmware bug
    elif k._flag == _FLAG_MONO:
        src_type = "single"
    elif k._flag == _FLAG_GROUP:
        src_type = "group"
    elif k._flag == _FLAG_STEREO:
        src_type = "stereo"
    else:
        src_type = "unassigned"

    channels = []
    if k._flag == _FLAG_MONO and k.src_ch != SRC_NONE and not k.is_auxin() and not k.is_sine():
        channels = [k.src_ch]
    elif k._flag == _FLAG_GROUP:
        channels = list(k._group_channels)
    elif k._flag == _FLAG_STEREO and k.src_ch != SRC_NONE:
        channels = [k.src_ch, k.src_ch + 1]
    # single_no_ch: channels stays [] — channel is unknown

    # ME-1 pan at +194: 0x00=hard left, 0x25=centre, 0x4A=hard right
    display_pan = k.pan

    # Per-channel level/pan for groups (from slot data)
    per_channel = {}
    if k._flag == _FLAG_GROUP:
        for ch in k._group_channels:
            slot_off = (ch - 1) * 4
            if slot_off + 4 <= len(k.slots):
                sl = k.slots[slot_off:slot_off + 4]
                per_channel[ch] = {
                    "level": sl[1] if sl[0] == 0x04 else LEVEL_OFF,
                    "pan":   sl[3] if sl[0] == 0x04 else PAN_CENTRE,
                }

    return {
        "idx":         idx,
        "label":       k.label,
        "src_type":    src_type,
        "channels":    channels,
        "pan":         display_pan,
        "level":       k.level,
        "assigned":    src_type != "unassigned",
        "raw_flag":    k._flag,
        "per_channel": per_channel,
    }

def preset_to_dict(p: Preset, idx: int) -> dict:
    return {
        "idx":      idx,
        "name":     p.name,
        "has_data": p.has_data,
        "keys":     [key_to_dict(k, i) for i, k in enumerate(p.keys)],
    }

_MID_FREQ_TABLE = {
    200:  (0x65, 0x96), 520:  (0x7e, 0x67), 840:  (0x8a, 0xdb),
    1100: (0x93, 0x3d), 1400: (0x99, 0x90), 1800: (0x9e, 0xa5),
    2100: (0xa2, 0xe5), 2400: (0xa6, 0x8c), 2700: (0xa9, 0xbf),
    3000: (0xac, 0x98), 3400: (0xaf, 0x29), 3700: (0xb1, 0x7f),
    4000: (0xb3, 0xa4), 4300: (0xb5, 0x9f), 4600: (0xb7, 0x76),
    5000: (0xb9, 0x2d),
}
_MID_FREQ_REVERSE = {v: k for k, v in _MID_FREQ_TABLE.items()}

def _read_eq(preset_idx: int = 0) -> dict:
    if _config is None or len(_config.presets[preset_idx]._tail) < 32:
        return {"lo": 0, "mid_gain": 0, "mid_freq": 200, "hi": 0}
    tail = _config.presets[preset_idx]._tail
    lo  = tail[9]  if tail[9]  < 128 else tail[9]  - 256
    mg  = tail[20] if tail[20] < 128 else tail[20] - 256
    hi  = tail[31] if tail[31] < 128 else tail[31] - 256
    mid_freq = _MID_FREQ_REVERSE.get((tail[24], tail[25]), 200)
    lim_byte = tail[42] if tail[42] < 128 else tail[42] - 256
    # Convert signed dBFS back to step index (0=off, 1-9)
    limiter  = 0 if lim_byte == 0 else round(abs(lim_byte) / 3)
    return {"lo": lo, "mid_gain": mg, "mid_freq": mid_freq, "hi": hi, "limiter": limiter}

def config_to_dict() -> dict:
    return {
        "filename": _filename,
        "presets":  [preset_to_dict(p, i) for i, p in enumerate(_config.presets)],
        "eq":       _read_eq(0),
    }

def apply_key_update(key: Key, data: dict):
    src_type = data.get("src_type", "unassigned")
    label    = data.get("label", "")
    pan      = int(data.get("pan", 0x25))  # ME-1 pan: 0x00=L, 0x25=C, 0x4A=R
    level    = int(data.get("level", LEVEL_OFF))
    channels = data.get("channels", [])

    if src_type == "auto":
        key.assign_auto()
    elif src_type == "auxin":
        key.assign_auxin()
    elif src_type == "sine":
        key.assign_sine()
    elif src_type == "single":
        if not channels:
            raise ValueError("Single channel requires a channel number")
        key.assign_mono(src_ch=int(channels[0]), label=label, pan=pan, level=level)
    elif src_type == "group":
        if not channels:
            raise ValueError("Group requires at least one channel selected")
        chs = sorted(int(c) for c in channels)
        key.assign_group(channels=chs, label=label, level=level, per_channel={int(k): {'level': v.get('level', LEVEL_UNITY), 'pan': v.get('pan', PAN_CENTRE)} for k,v in data.get('per_channel', {}).items()})
    else:
        key.assign_unassigned()  # always clears label and uses sentinel pan


# ── Routes ────────────────────────────────────────────────────────────────────

@app.route("/api/saved", methods=["GET"])
def list_saved():
    files = sorted(glob.glob(os.path.join(STORAGE_DIR, "*.ME1")))
    return jsonify([{"name": os.path.basename(f),
                     "size": os.path.getsize(f),
                     "mtime": int(os.path.getmtime(f))} for f in files])

@app.route("/api/saved/save", methods=["POST"])
def save_to_storage():
    global _config, _filename
    if _config is None:
        return jsonify({"error": "No config loaded"}), 400
    name = request.json.get("name", _filename).strip()
    if not name.upper().endswith(".ME1"):
        name += ".ME1"
    name = re.sub(r'[^A-Za-z0-9._-]', '_', name)[:32]
    path = os.path.join(STORAGE_DIR, name)
    with open(path, "wb") as f:
        f.write(_config._encode())
    return jsonify({"ok": True, "name": name})

@app.route("/api/saved/load/<name>", methods=["POST"])
def load_from_storage(name):
    global _config, _filename
    path = os.path.join(STORAGE_DIR, re.sub(r'[^A-Za-z0-9._-]', '_', name))
    if not os.path.exists(path):
        return jsonify({"error": "Not found"}), 404
    _config   = ME1Config.load(path)
    _filename = os.path.basename(path)
    return jsonify(config_to_dict())

@app.route("/api/saved/download/<name>", methods=["GET"])
def download_saved(name):
    path = os.path.join(STORAGE_DIR, re.sub(r'[^A-Za-z0-9._-]', '_', name))
    if not os.path.exists(path):
        return jsonify({"error": "Not found"}), 404
    with open(path, "rb") as f:
        data = f.read()
    buf = io.BytesIO(data)
    return send_file(buf, as_attachment=True, download_name=os.path.basename(path),
                     mimetype="application/octet-stream")

@app.route("/api/saved/delete/<name>", methods=["DELETE"])
def delete_saved(name):
    path = os.path.join(STORAGE_DIR, re.sub(r'[^A-Za-z0-9._-]', '_', name))
    if os.path.exists(path):
        os.remove(path)
    return jsonify({"ok": True})

@app.route("/")
def index():
    return render_template_string(HTML.replace("__ME1_IMG__", ME1_IMG))

@app.route("/api/config", methods=["GET"])
def get_config():
    global _config
    if _config is None:
        _config = ME1Config()
    return jsonify(config_to_dict())

@app.route("/api/upload", methods=["POST"])
def upload():
    global _config, _filename
    f = request.files.get("file")
    if not f:
        return jsonify({"error": "No file provided"}), 400
    data  = f.read()
    fname = f.filename or "upload.ME1"
    tmp   = tempfile.NamedTemporaryFile(delete=False, suffix=".ME1")
    tmp.write(data); tmp.close()
    try:
        if len(data) == 4096:
            preset = Preset.load(tmp.name)
            _config = ME1Config()
            _config.presets[0] = preset
            _config.presets[0].has_data = True
        else:
            _config = ME1Config.load(tmp.name)
        _filename = fname
        return jsonify(config_to_dict())
    except Exception as e:
        return jsonify({"error": str(e)}), 400
    finally:
        os.unlink(tmp.name)

@app.route("/api/update-eq", methods=["POST"])
def update_eq():
    global _config
    if _config is None:
        return jsonify({"error": "No config loaded"}), 400
    data = request.json
    preset_idx = int(data.get("preset_idx", 0))
    lo_gain  = int(data.get("lo_gain",  0))   # -12 to +12
    mid_gain = int(data.get("mid_gain", 0))   # -12 to +12
    mid_freq = int(data.get("mid_freq", 200)) # Hz index
    hi_gain  = int(data.get("hi_gain",  0))   # -12 to +12
    limiter  = int(data.get("limiter",  0))   # 0=off, 1-9 = -3 to -27 dBFS

    freq_bytes = _MID_FREQ_TABLE.get(mid_freq, _MID_FREQ_TABLE[200])

    p = _config.presets[preset_idx]
    tail = bytearray(p._tail)

    # EQ byte positions within the tail (confirmed from TEST55 analysis):
    # tail+9  = Lo gain  (signed byte)
    # tail+20 = Mid gain (signed byte)
    # tail+24,25 = Mid freq (2-byte lookup)
    # tail+31 = Hi gain  (signed byte)
    tail[9]  = lo_gain  & 0xFF
    tail[20] = mid_gain & 0xFF
    tail[24] = freq_bytes[0]
    tail[25] = freq_bytes[1]
    tail[31] = hi_gain  & 0xFF
    # Limiter: 0=off(0x00), steps 1-9 = -3dBFS to -27dBFS (step * -3 as signed byte)
    lim_db   = limiter * -3   # 0, -3, -6, ..., -27
    tail[42] = lim_db & 0xFF

    p._tail = bytes(tail)
    return jsonify({"ok": True})


@app.route("/api/update-key", methods=["POST"])
def update_key():
    global _config
    if _config is None:
        return jsonify({"error": "No config loaded"}), 400
    data  = request.json
    p_idx = int(data.get("preset_idx", 0))
    k_idx = int(data.get("key_idx", 0))
    if not (0 <= p_idx < _NPRESETS and 0 <= k_idx < _NKEYS):
        return jsonify({"error": "Index out of range"}), 400
    try:
        apply_key_update(_config.presets[p_idx].keys[k_idx], data)
        _config.presets[p_idx].has_data = True
        return jsonify(config_to_dict())
    except (NotImplementedError, Exception) as e:
        return jsonify({"error": str(e)}), 400

@app.route("/api/update-preset-name", methods=["POST"])
def update_preset_name():
    global _config
    if _config is None:
        return jsonify({"error": "No config loaded"}), 400
    data  = request.json
    p_idx = int(data.get("preset_idx", 0))
    name  = str(data.get("name", ""))[:8]
    if not (0 <= p_idx < _NPRESETS):
        return jsonify({"error": "Index out of range"}), 400
    _config.presets[p_idx].name = name
    # Naming a preset marks it as having data so it appears in the preset list
    if name.strip():
        _config.presets[p_idx].has_data = True
    return jsonify(config_to_dict())

@app.route("/api/rename", methods=["POST"])
def rename_file():
    global _filename
    import re as _re
    data = request.get_json(force=True)
    raw  = data.get("filename", "")
    base = _re.sub(r"[^A-Z0-9]", "", raw.upper().replace(".ME1", ""))[:8] or "UNTITLED"
    _filename = base + ".ME1"
    return jsonify({"filename": _filename})

@app.route("/api/new", methods=["POST"])
def new_config():
    global _config, _filename
    _config   = ME1Config()
    _filename = "untitled.ME1"
    return jsonify(config_to_dict())

@app.route("/api/download", methods=["GET"])
def download():
    global _config, _filename
    if _config is None:
        return jsonify({"error": "No config"}), 400
    buf = io.BytesIO(_config._encode())
    buf.seek(0)
    return send_file(buf, as_attachment=True,
                     download_name=_filename,
                     mimetype="application/octet-stream")


